+++ b/jsonschema.go
@@ -0,0 +1,247 @@
+package validator
+
+import (
+	"encoding/json"
+	"reflect"
+	"strconv"
+	"strings"
+)
+
+const jsonSchemaDraft07 = "http://json-schema.org/draft-07/schema#"
+
+// JSONSchema generates a JSON Schema (draft-07) document from the struct tags
+// on s. s must be a struct or a pointer to a struct.
+//
+// Property names are resolved using RegisterTagNameFunc when set, otherwise the
+// json struct tag (first segment, skipping "-"), otherwise the Go field name.
+//
+// Only a subset of validate tags are mapped to schema keywords. Cross-field
+// conditional tags, struct-level validators, custom validators, and map keys/endkeys
+// are not reflected in the generated schema. For richer metadata such as titles
+// and descriptions, consider github.com/invopop/jsonschema.
+func (v *Validate) JSONSchema(s interface{}) ([]byte, error) {
+	current := reflect.ValueOf(s)
+	typ := current.Type()
+
+	for typ.Kind() == reflect.Ptr {
+		if current.IsNil() {
+			current = reflect.Zero(typ.Elem())
+		} else {
+			current = current.Elem()
+		}
+		typ = typ.Elem()
+	}
+
+	if typ.Kind() != reflect.Struct {
+		return nil, &InvalidValidationError{Type: typ}
+	}
+
+	schema := v.buildJSONSchemaObject(current, typ)
+	schema["$schema"] = jsonSchemaDraft07
+
+	return json.Marshal(schema)
+}
+
+func (v *Validate) buildJSONSchemaObject(current reflect.Value, typ reflect.Type) map[string]interface{} {
+	schema := map[string]interface{}{
+		"type":       "object",
+		"properties": map[string]interface{}{},
+	}
+
+	cs := v.extractStructCache(current, typ.Name())
+	properties := schema["properties"].(map[string]interface{})
+	required := make([]string, 0)
+
+	for _, f := range cs.fields {
+		fld := typ.Field(f.idx)
+		propName := v.jsonSchemaPropertyName(fld)
+		if propName == "" {
+			continue
+		}
+
+		fieldVal := current.Field(f.idx)
+		fieldType := fld.Type
+		propSchema, isRequired := v.buildJSONSchemaProperty(fieldVal, fieldType, f.cTags)
+		if propSchema == nil {
+			continue
+		}
+
+		properties[propName] = propSchema
+		if isRequired {
+			required = append(required, propName)
+		}
+	}
+
+	if len(required) > 0 {
+		schema["required"] = required
+	}
+
+	return schema
+}
+
+func (v *Validate) jsonSchemaPropertyName(fld reflect.StructField) string {
+	if v.hasTagNameFunc {
+		name := v.tagNameFunc(fld)
+		if len(name) > 0 || v.omitBlankFieldNames {
+			return name
+		}
+	}
+
+	if jsonTag := fld.Tag.Get("json"); jsonTag != "" {
+		name := strings.SplitN(jsonTag, ",", 2)[0]
+		if name == "-" {
+			return ""
+		}
+		if name != "" {
+			return name
+		}
+	}
+
+	return fld.Name
+}
+
+func (v *Validate) buildJSONSchemaProperty(current reflect.Value, typ reflect.Type, ct *cTag) (map[string]interface{}, bool) {
+	for typ.Kind() == reflect.Ptr {
+		typ = typ.Elem()
+		if current.IsValid() && !current.IsNil() {
+			current = current.Elem()
+		}
+	}
+
+	switch typ.Kind() {
+	case reflect.Struct:
+		if typ == timeType {
+			return v.applyCTagsToSchema(map[string]interface{}{"type": "string"}, ct, typ), v.cTagsRequireField(ct)
+		}
+		return v.buildJSONSchemaObject(current, typ), v.cTagsRequireField(ct)
+	case reflect.Slice, reflect.Array:
+		schema := map[string]interface{}{"type": "array"}
+		items, _ := v.buildJSONSchemaFromCTags(current, typ.Elem(), ct)
+		if items != nil {
+			schema["items"] = items
+		}
+		return v.applyCTagsToSchema(schema, ct, typ), v.cTagsRequireField(ct)
+	default:
+		schema := map[string]interface{}{}
+		v.setJSONSchemaType(schema, typ)
+		return v.applyCTagsToSchema(schema, ct, typ), v.cTagsRequireField(ct)
+	}
+}
+
+func (v *Validate) buildJSONSchemaFromCTags(current reflect.Value, typ reflect.Type, ct *cTag) (map[string]interface{}, bool) {
+	var diveCT *cTag
+
+	for tag := ct; tag != nil; tag = tag.next {
+		if tag.typeof == typeDive {
+			diveCT = tag.next
+			break
+		}
+	}
+
+	if diveCT != nil {
+		if current.IsValid() && current.Kind() == reflect.Slice && current.Len() > 0 {
+			current = current.Index(0)
+		}
+		prop, _ := v.buildJSONSchemaProperty(current, typ, diveCT)
+		return prop, false
+	}
+
+	prop, _ := v.buildJSONSchemaProperty(reflect.Value{}, typ, ct)
+	return prop, false
+}
+
+func (v *Validate) cTagsRequireField(ct *cTag) bool {
+	for tag := ct; tag != nil; tag = tag.next {
+		if tag.hasTag && tag.tag == requiredTag {
+			return true
+		}
+	}
+	return false
+}
+
+func (v *Validate) setJSONSchemaType(schema map[string]interface{}, typ reflect.Type) {
+	switch typ.Kind() {
+	case reflect.String:
+		schema["type"] = "string"
+	case reflect.Bool:
+		schema["type"] = "boolean"
+	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64,
+		reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64:
+		schema["type"] = "integer"
+	case reflect.Float32, reflect.Float64:
+		schema["type"] = "number"
+	default:
+		schema["type"] = "string"
+	}
+}
+
+func (v *Validate) applyCTagsToSchema(schema map[string]interface{}, ct *cTag, typ reflect.Type) map[string]interface{} {
+	if schema == nil {
+		schema = map[string]interface{}{}
+	}
+
+	isString := typ.Kind() == reflect.String
+
+	for tag := ct; tag != nil; tag = tag.next {
+		if !tag.hasTag {
+			continue
+		}
+
+		switch tag.typeof {
+		case typeDive, typeOmitEmpty, typeOmitNil, typeOmitZero, typeStructOnly, typeNoStructLevel, typeOr, typeKeys, typeEndKeys, typeIsDefault:
+			continue
+		}
+
+		switch tag.tag {
+		case requiredTag:
+			continue
+		case "min":
+			if isString {
+				if n, err := strconv.ParseInt(tag.param, 10, 64); err == nil {
+					schema["minLength"] = n
+				}
+			} else {
+				if n, err := parseJSONSchemaNumber(tag.param); err == nil {
+					schema["minimum"] = n
+				}
+			}
+		case "max":
+			if isString {
+				if n, err := strconv.ParseInt(tag.param, 10, 64); err == nil {
+					schema["maxLength"] = n
+				}
+			} else {
+				if n, err := parseJSONSchemaNumber(tag.param); err == nil {
+					schema["maximum"] = n
+				}
+			}
+		case "len":
+			if n, err := strconv.ParseInt(tag.param, 10, 64); err == nil {
+				if isString {
+					schema["minLength"] = n
+					schema["maxLength"] = n
+				} else {
+					schema["minItems"] = n
+					schema["maxItems"] = n
+				}
+			}
+		case "oneof":
+			schema["enum"] = strings.Fields(tag.param)
+		case "email":
+			schema["format"] = "email"
+		case "url":
+			schema["format"] = "uri"
+		case "uuid", "uuid3", "uuid4", "uuid5":
+			schema["format"] = "uuid"
+		}
+	}
+
+	return schema
+}
+
+func parseJSONSchemaNumber(param string) (interface{}, error) {
+	if strings.Contains(param, ".") {
+		return strconv.ParseFloat(param, 64)
+	}
+	return strconv.ParseInt(param, 10, 64)
+}
diff --git a/jsonschema_test.go b/jsonschema_test.go
new file mode 100644
index 0000000..0561c74
--- /dev/null
+++ b/jsonschema_test.go
@@ -0,0 +1,234 @@
+package validator
+
+import (
+	"encoding/json"
+	"testing"
+
+	. "github.com/go-playground/assert/v2"
+)
+
+func assertJSONSchemaRoundTrip(t *testing.T, schema []byte) map[string]interface{} {
+	t.Helper()
+
+	var parsed map[string]interface{}
+	err := json.Unmarshal(schema, &parsed)
+	Equal(t, err, nil)
+
+	_, err = json.Marshal(parsed)
+	Equal(t, err, nil)
+
+	return parsed
+}
+
+func TestJSONSchema_required(t *testing.T) {
+	t.Run("required field in top-level required array", func(t *testing.T) {
+		type Config struct {
+			Name string `validate:"required"`
+			Note string
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		Equal(t, parsed["$schema"], jsonSchemaDraft07)
+		Equal(t, parsed["type"], "object")
+
+		required, ok := parsed["required"].([]interface{})
+		Equal(t, ok, true)
+		Equal(t, len(required), 1)
+		Equal(t, required[0], "Name")
+	})
+}
+
+func TestJSONSchema_stringConstraints(t *testing.T) {
+	t.Run("min max len map to string length keywords", func(t *testing.T) {
+		type Config struct {
+			MinField string `validate:"min=1"`
+			MaxField string `validate:"max=10"`
+			LenField string `validate:"len=5"`
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+
+		minField := properties["MinField"].(map[string]interface{})
+		Equal(t, minField["type"], "string")
+		Equal(t, minField["minLength"], float64(1))
+
+		maxField := properties["MaxField"].(map[string]interface{})
+		Equal(t, maxField["maxLength"], float64(10))
+
+		lenField := properties["LenField"].(map[string]interface{})
+		Equal(t, lenField["minLength"], float64(5))
+		Equal(t, lenField["maxLength"], float64(5))
+	})
+}
+
+func TestJSONSchema_oneof(t *testing.T) {
+	t.Run("oneof becomes enum", func(t *testing.T) {
+		type Config struct {
+			Mode string `validate:"oneof=a b c"`
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+		mode := properties["Mode"].(map[string]interface{})
+
+		enum, ok := mode["enum"].([]interface{})
+		Equal(t, ok, true)
+		Equal(t, enum, []interface{}{"a", "b", "c"})
+	})
+}
+
+func TestJSONSchema_formats(t *testing.T) {
+	t.Run("email url uuid map to format", func(t *testing.T) {
+		type Config struct {
+			Email string `validate:"email"`
+			URL   string `validate:"url"`
+			ID    string `validate:"uuid"`
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+
+		Equal(t, properties["Email"].(map[string]interface{})["format"], "email")
+		Equal(t, properties["URL"].(map[string]interface{})["format"], "uri")
+		Equal(t, properties["ID"].(map[string]interface{})["format"], "uuid")
+	})
+}
+
+func TestJSONSchema_nestedStruct(t *testing.T) {
+	t.Run("nested struct becomes object properties", func(t *testing.T) {
+		type Inner struct {
+			Value string `validate:"required"`
+		}
+
+		type Config struct {
+			Nested Inner
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+		nested := properties["Nested"].(map[string]interface{})
+
+		Equal(t, nested["type"], "object")
+
+		nestedProps := nested["properties"].(map[string]interface{})
+		value := nestedProps["Value"].(map[string]interface{})
+		Equal(t, value["type"], "string")
+
+		nestedRequired := nested["required"].([]interface{})
+		Equal(t, len(nestedRequired), 1)
+		Equal(t, nestedRequired[0], "Value")
+	})
+}
+
+func TestJSONSchema_dive(t *testing.T) {
+	t.Run("dive on slice sets items schema", func(t *testing.T) {
+		type Config struct {
+			Tags []string `validate:"dive,min=1,max=10"`
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+		tags := properties["Tags"].(map[string]interface{})
+
+		Equal(t, tags["type"], "array")
+
+		items := tags["items"].(map[string]interface{})
+		Equal(t, items["type"], "string")
+		Equal(t, items["minLength"], float64(1))
+		Equal(t, items["maxLength"], float64(10))
+	})
+}
+
+func TestJSONSchema_jsonPropertyNames(t *testing.T) {
+	t.Run("json tag names used when no RegisterTagNameFunc", func(t *testing.T) {
+		type Config struct {
+			HostName string `json:"host_name" validate:"required"`
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+		_, ok := properties["host_name"]
+		Equal(t, ok, true)
+		_, ok = properties["HostName"]
+		Equal(t, ok, false)
+	})
+}
+
+func TestJSONSchema_skipTag(t *testing.T) {
+	t.Run("validate dash omits field from schema", func(t *testing.T) {
+		type Config struct {
+			Public string `validate:"required"`
+			Secret string `validate:"-"`
+		}
+
+		validate := New()
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+		_, ok := properties["Public"]
+		Equal(t, ok, true)
+		_, ok = properties["Secret"]
+		Equal(t, ok, false)
+	})
+}
+
+func TestJSONSchema_alias(t *testing.T) {
+	t.Run("RegisterAlias expands to same constraints as target tags", func(t *testing.T) {
+		type Config struct {
+			Address string `validate:"mail"`
+		}
+
+		validate := New()
+		validate.RegisterAlias("mail", "email")
+
+		schema, err := validate.JSONSchema(Config{})
+		Equal(t, err, nil)
+
+		parsed := assertJSONSchemaRoundTrip(t, schema)
+		properties := parsed["properties"].(map[string]interface{})
+		address := properties["Address"].(map[string]interface{})
+		Equal(t, address["type"], "string")
+		Equal(t, address["format"], "email")
+	})
+}
+
+func TestJSONSchema_invalidInput(t *testing.T) {
+	t.Run("non struct returns InvalidValidationError", func(t *testing.T) {
+		validate := New()
+		_, err := validate.JSONSchema("not a struct")
+		NotEqual(t, err, nil)
+		_, ok := err.(*InvalidValidationError)
+		Equal(t, ok, true)
+	})
+}
